#include<bits/stdc++.h>
using namespace std;
const int MAXN = 2e5 + 7;
struct Node {
	int left, right;
} a[ MAXN ];

int n;
void input() {
	for (int i = 1; i <= n; i++) {
		cin >> a[i].left >> a[i].right;
	}
}
int recursion(int x) {
	if (!x) return 0;
	return max(recursion(a[x].left), recursion(a[x].right)) + 1;
}int main(){
	cin>>n;
	input();
	cout<<recursion(1);
	return 0;
}
